  1→//! Setup file compilation and subprocess execution for the Rust frontend.
  2→//!
  3→//! Setup files are Rust source files compiled to binaries and executed as
  4→//! subprocesses. The subprocess receives setup parameters as JSON on stdin
  5→//! and returns a JSON context object on stdout. This context is passed to
  6→//! subsequent Execute commands so frontends can restore setup state.
  7→
  8→use std::io;
  9→use std::path::Path;
 10→use std::process::Command;
 11→
 12→use crate::protocol::{SetupContextStack, SetupLevel};
 13→
 14→/// Result of executing a setup file subprocess.
 15→#[derive(Debug)]
 16→pub struct SetupResult {
 17→    /// Opaque context value returned by the setup subprocess (JSON on stdout).
 18→    pub context: serde_json::Value,
 19→}
 20→
 21→/// Errors that can occur during setup file compilation or execution.
 22→#[derive(Debug)]
 23→pub enum SetupError {
 24→    FileNotFound(String),
 25→    CompilationFailed(String),
 26→    ExecutionFailed(String),
 27→    InvalidOutput(String),
 28→}
 29→
 30→impl std::fmt::Display for SetupError {
 31→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 32→        match self {
 33→            Self::FileNotFound(path) => write!(f, "setup file not found: {path}"),
 34→            Self::CompilationFailed(msg) => write!(f, "setup compilation failed: {msg}"),
 35→            Self::ExecutionFailed(msg) => write!(f, "setup execution failed: {msg}"),
 36→            Self::InvalidOutput(msg) => write!(f, "setup produced invalid output: {msg}"),
 37→        }
 38→    }
 39→}
 40→
 41→impl std::error::Error for SetupError {}
 42→
 43→impl From<SetupError> for io::Error {
 44→    fn from(e: SetupError) -> Self {
 45→        io::Error::other(e.to_string())
 46→    }
 47→}
 48→
 49→/// Compile a Rust setup file to a temporary binary.
 50→/// Returns the path to the compiled binary.
 51→fn compile_setup_file(file_path: &Path) -> Result<std::path::PathBuf, SetupError> {
 52→    if !file_path.exists() {
 53→        return Err(SetupError::FileNotFound(
 54→            file_path.to_string_lossy().into_owned(),
 55→        ));
 56→    }
 57→
 58→    let out_dir = std::env::temp_dir().join(format!("shatter-setup-{}", std::process::id()));
 59→    std::fs::create_dir_all(&out_dir).map_err(|e| {
 60→        SetupError::CompilationFailed(format!("failed to create output directory: {e}"))
 61→    })?;
 62→
 63→    let stem = file_path
 64→        .file_stem()
 65→        .and_then(|s| s.to_str())
 66→        .unwrap_or("setup");
 67→    let binary_path = out_dir.join(stem);
 68→
 69→    let output = Command::new("rustc")
 70→        .arg(file_path)
 71→        .arg("-o")
 72→        .arg(&binary_path)
 73→        .output()
 74→        .map_err(|e| SetupError::CompilationFailed(format!("failed to invoke rustc: {e}")))?;
 75→
 76→    if !output.status.success() {
 77→        let stderr = String::from_utf8_lossy(&output.stderr);
 78→        return Err(SetupError::CompilationFailed(stderr.into_owned()));
 79→    }
 80→
 81→    Ok(binary_path)
 82→}
 83→
 84→/// Execute a compiled setup binary as a subprocess.
 85→/// Passes setup parameters as JSON on stdin, reads context JSON from stdout.
 86→fn run_setup_binary(
 87→    binary_path: &Path,
 88→    level: SetupLevel,
 89→    scope: &str,
 90→    parent_context: Option<&SetupContextStack>,
 91→) -> Result<SetupResult, SetupError> {
 92→    let input = serde_json::json!({
 93→        "level": level,
 94→        "scope": scope,
 95→        "parent_context": parent_context,
 96→    });
 97→    let input_json = serde_json::to_string(&input)
 98→        .map_err(|e| SetupError::ExecutionFailed(format!("failed to serialize input: {e}")))?;
 99→
100→    let mut child = Command::new(binary_path)
101→        .stdin(std::process::Stdio::piped())
102→        .stdout(std::process::Stdio::piped())
103→        .stderr(std::process::Stdio::piped())
104→        .spawn()
105→        .map_err(|e| SetupError::ExecutionFailed(format!("failed to spawn setup binary: {e}")))?;
106→
107→    if let Some(stdin) = child.stdin.take() {
108→        use std::io::Write;
109→        let mut stdin = stdin;
110→        let _ = stdin.write_all(input_json.as_bytes());
111→    }
112→
113→    let output = child
114→        .wait_with_output()
115→        .map_err(|e| SetupError::ExecutionFailed(format!("failed to wait for setup binary: {e}")))?;
116→
117→    if !output.status.success() {
118→        let stderr = String::from_utf8_lossy(&output.stderr);
119→        return Err(SetupError::ExecutionFailed(format!(
120→            "setup binary exited with {}: {}",
121→            output.status, stderr
122→        )));
123→    }
124→
125→    let stdout = String::from_utf8_lossy(&output.stdout);
126→    let context: serde_json::Value = serde_json::from_str(stdout.trim()).map_err(|e| {
127→        SetupError::InvalidOutput(format!("expected JSON on stdout, got: {e}"))
128→    })?;
129→
130→    Ok(SetupResult { context })
131→}
132→
133→/// Run a complete setup: compile the file and execute the resulting binary.
134→/// Returns the opaque context value for downstream Execute commands.
135→pub fn run_setup(
136→    file_path: &Path,
137→    level: SetupLevel,
138→    scope: &str,
139→    parent_context: Option<&SetupContextStack>,
140→) -> Result<SetupResult, SetupError> {
141→    let binary_path = compile_setup_file(file_path)?;
142→    let result = run_setup_binary(&binary_path, level, scope, parent_context);
143→
144→    // Best-effort cleanup of the compiled binary
145→    let _ = std::fs::remove_file(&binary_path);
146→
147→    result
148→}
149→
150→/// Tear down state for a given scope and level.
151→/// Currently a no-op since teardown state is managed by the core engine.
152→/// Future: could invoke a teardown file or function.
153→pub fn run_teardown(
154→    _level: SetupLevel,
155→    _scope: &str,
156→) -> Result<(), SetupError> {
157→    Ok(())
158→}
