/**
 * Protocol types for communication between the Rust core and TypeScript frontend.
 *
 * All messages are newline-delimited JSON over stdin/stdout. The core sends
 * Request messages and receives Response messages back. Every message includes
 * a protocol version for compatibility checking.
 */

export const PROTOCOL_VERSION = "0.1.0";
export const FRONTEND_LANGUAGE = "typescript";

// ---------------------------------------------------------------------------
// Request: Core → Frontend
// ---------------------------------------------------------------------------

export type SetupMode = "per_function" | "per_execution";

export type SetupLevel = "session" | "file" | "function" | "execution";

export interface SetupContextEntry {
  level: SetupLevel;
  context: unknown;
}

export interface SetupContextStack {
  contexts: SetupContextEntry[];
}

export type GeneratorKind = "type_name" | "param_name";

export type Command =
  | "handshake"
  | "analyze"
  | "instrument"
  | "execute"
  | "setup"
  | "teardown"
  | "generate"
  | "shutdown";

export interface MockConfig {
  symbol: string;
  return_values: unknown[];
  should_track_calls: boolean;
  default_behavior: "return_generated" | "repeat_last" | "throw_error" | "passthrough";
}

interface BaseRequest {
  protocol_version: string;
  id: number;
  command: Command;
}

export interface HandshakeRequest extends BaseRequest {
  command: "handshake";
  capabilities: string[];
}

export interface AnalyzeRequest extends BaseRequest {
  command: "analyze";
  file: string;
  function?: string | null;
  project_root?: string | null;
}

export interface InstrumentRequest extends BaseRequest {
  command: "instrument";
  file: string;
  function: string;
  mocks: MockConfig[];
  project_root?: string | null;
}

export interface ExecuteRequest extends BaseRequest {
  command: "execute";
  function: string;
  inputs: unknown[];
  mocks: MockConfig[];
  setup_context?: SetupContextStack | null;
}

export interface SetupRequest extends BaseRequest {
  command: "setup";
  file: string;
  scope: string;
  level: SetupLevel;
  parent_context?: SetupContextStack | null;
  project_root?: string | null;
}

export interface TeardownRequest extends BaseRequest {
  command: "teardown";
  scope: string;
  level: SetupLevel;
}

export interface GenerateRequest extends BaseRequest {
  command: "generate";
  file: string;
  name: string;
  kind: GeneratorKind;
  recipe?: unknown;
  project_root?: string | null;
}

export interface ShutdownRequest extends BaseRequest {
  command: "shutdown";
}

export type Request =
  | HandshakeRequest
  | AnalyzeRequest
  | InstrumentRequest
  | ExecuteRequest
  | SetupRequest
  | TeardownRequest
  | GenerateRequest
  | ShutdownRequest;

// ---------------------------------------------------------------------------
// Response: Frontend → Core
// ---------------------------------------------------------------------------

export type ResponseStatus =
  | "handshake"
  | "analyze"
  | "instrument"
  | "execute"
  | "setup"
  | "teardown_ack"
  | "generate"
  | "shutdown_ack"
  | "error";

export type ErrorCode =
  | "file_not_found"
  | "function_not_found"
  | "parse_error"
  | "instrumentation_failed"
  | "execution_timeout"
  | "execution_crash"
  | "version_mismatch"
  | "invalid_request"
  | "internal_error";

interface BaseResponse {
  protocol_version: string;
  id: number;
  status: ResponseStatus;
}

export interface HandshakeResponse extends BaseResponse {
  status: "handshake";
  frontend_version: string;
  language: string;
  capabilities: string[];
}

export interface AnalyzeResponse extends BaseResponse {
  status: "analyze";
  functions: FunctionAnalysis[];
}

export interface InstrumentResponse extends BaseResponse {
  status: "instrument";
  instrumented: boolean;
  output_file: string | null;
  instrumentable_line_count?: number;
}

export interface ExecuteResponse extends BaseResponse {
  status: "execute";
  return_value: unknown;
  thrown_error: ErrorInfo | null;
  branch_path: BranchDecision[];
  lines_executed: number[];
  calls_to_external: ExternalCall[];
  path_constraints: SymConstraint[];
  side_effects: SideEffect[];
  performance: PerformanceMetrics;
  capture_truncation?: TruncationInfo;
  scope_events?: TraceEvent[];
}

export interface SetupResponse extends BaseResponse {
  status: "setup";
  setup_context: unknown;
}

export interface TeardownAckResponse extends BaseResponse {
  status: "teardown_ack";
}

export interface GenerateResponse extends BaseResponse {
  status: "generate";
  value: unknown;
  generator_id: string;
  recipe?: unknown;
}

export interface ShutdownAckResponse extends BaseResponse {
  status: "shutdown_ack";
}

export interface ErrorResponse extends BaseResponse {
  status: "error";
  code: ErrorCode;
  message: string;
  details?: unknown;
}

export type Response =
  | HandshakeResponse
  | AnalyzeResponse
  | InstrumentResponse
  | ExecuteResponse
  | SetupResponse
  | TeardownAckResponse
  | GenerateResponse
  | ShutdownAckResponse
  | ErrorResponse;

// ---------------------------------------------------------------------------
// Supporting types
// ---------------------------------------------------------------------------

/** A literal constant extracted from source code for use as a candidate test input. */
export type LiteralValue =
  | { type: "int"; value: number }
  | { type: "float"; value: number }
  | { type: "str"; value: string }
  | { type: "bool"; value: boolean }
  | { type: "regex"; pattern: string };

export interface CryptoBoundary {
  symbol: string;
  source_module: string;
  direction: "encrypt" | "decrypt" | "both";
  output: "ciphertext" | "plaintext" | "key" | "hash" | "signature" | "verified";
  param_roles: Record<string, "key" | "data" | "iv" | "nonce" | "tag" | "aad" | "algorithm">;
  call_sites: number[];
}

export interface FunctionAnalysis {
  name: string;
  exported?: boolean;
  params: ParamInfo[];
  branches: BranchInfo[];
  dependencies: ExternalDependency[];
  return_type: TypeInfo;
  start_line: number;
  end_line: number;
  literals?: LiteralValue[];
  crypto_boundaries?: CryptoBoundary[];
}

export interface ParamInfo {
  name: string;
  type: TypeInfo;
  type_name?: string;
}

/** Well-known complex types beyond primitives and structural types. */
export type ComplexKind =
  | "date" | "date_time" | "time" | "duration"
  | "reg_exp" | "char" | "symbol"
  | "big_int" | "big_decimal" | "complex" | "rational" | "range"
  | "buffer" | "bit_set"
  | "error" | "option" | "result"
  | "closure" | "iterator"
  | "url" | "ip_address"
  | "uuid"
  | "path"
  | "money" | "sem_ver" | "email" | "mime_type" | "color" | "geo_point" | "locale"
  | "rune" | "go_byte";

export type TypeInfo =
  | { kind: "int" }
  | { kind: "float" }
  | { kind: "str" }
  | { kind: "bool" }
  | { kind: "unknown" }
  | { kind: "array"; element: TypeInfo }
  | { kind: "object"; fields: [string, TypeInfo][] }
  | { kind: "union"; variants: TypeInfo[] }
  | { kind: "nullable"; inner: TypeInfo }
  | { kind: "complex"; complex_kind: ComplexKind; metadata?: Record<string, unknown>; inner?: TypeInfo }
  | { kind: "opaque"; label: string };

export interface BranchInfo {
  id: number;
  line: number;
  condition_text: string;
  condition: SymExpr | null;
  branch_type: BranchType;
}

export type BranchType =
  | "if"
  | "else_if"
  | "switch"
  | "ternary"
  | "logical_and"
  | "logical_or"
  | "while"
  | "for";

export type SymExpr =
  | { kind: "param"; name: string; path: string[] }
  | SymExprConst
  | { kind: "bin_op"; op: BinOpKind; left: SymExpr; right: SymExpr }
  | { kind: "un_op"; op: UnOpKind; operand: SymExpr }
  | { kind: "call"; name: string; receiver: SymExpr | null; args: SymExpr[] }
  | { kind: "unknown" };

/** Const variant of SymExpr. Flattened to match Rust serde serialization. */
export type SymExprConst =
  | { kind: "const"; type: "int"; value: number }
  | { kind: "const"; type: "float"; value: number }
  | { kind: "const"; type: "str"; value: string }
  | { kind: "const"; type: "bool"; value: boolean }
  | { kind: "const"; type: "null" }
  | { kind: "const"; type: "undefined" }
  | { kind: "const"; type: "complex"; value: { kind: ComplexKind; repr: SymExprConst } };

export type BinOpKind =
  | "eq" | "ne" | "lt" | "le" | "gt" | "ge"
  | "add" | "sub" | "mul" | "div" | "mod"
  | "and" | "or"
  | "bitwise_and" | "bitwise_or" | "bitwise_xor"
  | "in" | "instance_of";

export type UnOpKind = "not" | "neg" | "bitwise_not" | "typeof";

export interface BranchDecision {
  branch_id: number;
  line: number;
  taken: boolean;
  constraint: SymConstraint;
}

export type ScopeEvent =
  | { kind: "loop_enter"; loop_id: number }
  | { kind: "loop_exit"; loop_id: number }
  | { kind: "call_enter"; call_site_id: number }
  | { kind: "call_exit"; call_site_id: number };

export type TraceEvent =
  | { type: "branch"; decision: BranchDecision }
  | { type: "scope"; event: ScopeEvent };

export type SymConstraint =
  | { kind: "expr"; expr: SymExpr }
  | { kind: "unknown"; hint: string };

export interface ExternalCall {
  symbol: string;
  args: unknown[];
  return_value: unknown;
}

export interface ExternalDependency {
  kind: DependencyKind;
  symbol: string;
  source_module: string;
  return_type: TypeInfo;
  param_types: TypeInfo[];
  call_sites: number[];
}

export type DependencyKind =
  | "function_call"
  | "method_call"
  | "property_access"
  | "module_import";

export type SideEffect =
  | { kind: "console_output"; level: string; message: string }
  | { kind: "file_write"; path: string; content: string }
  | { kind: "network_request"; method: string; url: string; body: unknown }
  | { kind: "environment_read"; variable: string; value: string | null }
  | { kind: "global_mutation"; name: string }
  | { kind: "thrown_error"; error_type: string; message: string; stack: string | null }
  | { kind: "global_state_change"; variable: string; before: unknown; after: unknown };

export type ErrorCategory = "validation" | "runtime" | "infrastructure" | "unknown";

export interface ErrorInfo {
  error_type: string;
  message: string;
  stack: string | null;
  error_category?: ErrorCategory;
}

export interface TruncationInfo {
  was_truncated: boolean;
  original_lines: number;
  original_bytes: number;
}

export interface PerformanceMetrics {
  wall_time_ms: number;
  cpu_time_us: number;
  heap_used_bytes: number;
  heap_allocated_bytes: number;
}

package protocol

// Error codes matching the Shatter protocol ErrorCode enum.
const (
	ErrInvalidRequest   = "invalid_request"
	ErrFileNotFound     = "file_not_found"
	ErrVersionMismatch  = "version_mismatch"
	ErrExecutionTimeout = "execution_timeout"
	ErrExecutionCrash   = "execution_crash"
	ErrInternalError    = "internal_error"
	ErrNotSupported     = "not_supported"
	ErrParseError       = "parse_error"
)

// CommandCapabilities lists the standard protocol commands this frontend supports.
var CommandCapabilities = []string{"analyze", "execute", "instrument", "generate", "setup", "teardown"}

/**
 * Property-based tests using fast-check for protocol types and SymExpr.
 *
 * Validates serialization round-trips and structural invariants that
 * hand-written fixtures might miss.
 */
import fc from "fast-check";
import ts from "typescript";
import type {
  BinOpKind,
  UnOpKind,
  SymExpr,
  SymExprConst,
  TypeInfo,
  ComplexKind,
  BranchType,
  BranchDecision,
  SymConstraint,
  ErrorCode,
  SideEffect,
  PerformanceMetrics,
  TraceEvent,
  ScopeEvent,
  HandshakeRequest,
  AnalyzeRequest,
  ExecuteRequest,
  ShutdownRequest,
  SetupRequest,
  TeardownRequest,
  SetupLevel,
  SetupContextEntry,
  SetupContextStack,
  Request,
  HandshakeResponse,
  AnalyzeResponse,
  ErrorResponse,
  Response,
  FunctionAnalysis,
  ParamInfo,
  BranchInfo,
  ErrorInfo,
} from "./protocol.js";
import { PROTOCOL_VERSION } from "./protocol.js";
import { buildSymExpr, buildSymExprWithFlow } from "./instrumentor.js";

// ---------------------------------------------------------------------------
// Arbitraries — leaf types
// ---------------------------------------------------------------------------

const arbIdent = fc.stringMatching(/^[a-zA-Z_][a-zA-Z0-9_]{0,12}$/);
const arbShortString = fc.string({ maxLength: 30 });

const arbBinOpKind: fc.Arbitrary<BinOpKind> = fc.constantFrom(
  "eq", "ne", "lt", "le", "gt", "ge",
  "add", "sub", "mul", "div", "mod",
  "and", "or",
  "bitwise_and", "bitwise_or", "bitwise_xor",
  "in", "instance_of",
);

const arbUnOpKind: fc.Arbitrary<UnOpKind> = fc.constantFrom(
  "not", "neg", "bitwise_not", "typeof",
);

const arbComplexKind: fc.Arbitrary<ComplexKind> = fc.constantFrom(
  "date", "date_time", "time", "duration",
  "reg_exp", "char", "symbol",
  "big_int", "big_decimal", "complex", "rational", "range",
  "buffer", "bit_set",
  "error", "option", "result",
  "closure", "iterator",
  "url", "ip_address",
  "uuid", "path",
  "money", "sem_ver", "email", "mime_type", "color", "geo_point", "locale",
  "rune", "go_byte",
);

const arbBranchType: fc.Arbitrary<BranchType> = fc.constantFrom(
  "if", "else_if", "switch", "ternary",
  "logical_and", "logical_or", "while", "for",
);

const arbErrorCode: fc.Arbitrary<ErrorCode> = fc.constantFrom(
  "file_not_found", "function_not_found", "parse_error",
  "instrumentation_failed", "execution_timeout", "execution_crash",
  "version_mismatch", "invalid_request", "internal_error",
);

// ---------------------------------------------------------------------------
// Arbitraries — recursive types
// ---------------------------------------------------------------------------

const arbSymExprConst: fc.Arbitrary<SymExprConst> = fc.oneof(
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("int" as const), value: fc.integer({ min: -10000, max: 10000 }) }),
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("float" as const), value: fc.integer({ min: -1000, max: 1000 }) }),
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("str" as const), value: arbShortString }),
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("bool" as const), value: fc.boolean() }),
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("null" as const) }),
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("undefined" as const) }),
);

const arbSymExpr: fc.Arbitrary<SymExpr> = fc.letrec<{ expr: SymExpr }>(tie => ({
  expr: fc.oneof(
    { depthIdentifier: "symexpr", maxDepth: 3 },
    fc.record({
      kind: fc.constant("param" as const),
      name: arbIdent,
      path: fc.array(arbIdent, { maxLength: 3 }),
    }),
    arbSymExprConst,
    fc.record({ kind: fc.constant("unknown" as const) }),
    fc.record({
      kind: fc.constant("bin_op" as const),
      op: arbBinOpKind,
      left: tie("expr"),
      right: tie("expr"),
    }),
    fc.record({
      kind: fc.constant("un_op" as const),
      op: arbUnOpKind,
      operand: tie("expr"),
    }),
  ),
})).expr;

const arbTypeInfoLeaf: fc.Arbitrary<TypeInfo> = fc.oneof(
  fc.record({ kind: fc.constant("int" as const) }),
  fc.record({ kind: fc.constant("float" as const) }),
  fc.record({ kind: fc.constant("str" as const) }),
  fc.record({ kind: fc.constant("bool" as const) }),
  fc.record({ kind: fc.constant("unknown" as const) }),
  fc.record({ kind: fc.constant("opaque" as const), label: arbIdent }),
);

const arbTypeInfo: fc.Arbitrary<TypeInfo> = fc.letrec<{ ti: TypeInfo }>(tie => ({
  ti: fc.oneof(
    { depthIdentifier: "typeinfo", maxDepth: 2 },
    arbTypeInfoLeaf,
    fc.record({ kind: fc.constant("array" as const), element: tie("ti") }),
    fc.record({
      kind: fc.constant("nullable" as const),
      inner: tie("ti"),
    }),
    fc.record({
      kind: fc.constant("union" as const),
      variants: fc.array(tie("ti"), { minLength: 2, maxLength: 4 }),
    }),
  ),
})).ti;

// ---------------------------------------------------------------------------
// Arbitraries — protocol records
// ---------------------------------------------------------------------------

const arbSymConstraint: fc.Arbitrary<SymConstraint> = fc.oneof(
  fc.record({ kind: fc.constant("expr" as const), expr: arbSymExpr }),
  fc.record({ kind: fc.constant("unknown" as const), hint: arbShortString }),
);

const arbBranchDecision: fc.Arbitrary<BranchDecision> = fc.record({
  branch_id: fc.nat(100),
  line: fc.integer({ min: 1, max: 500 }),
  taken: fc.boolean(),
  constraint: arbSymConstraint,
});

const arbScopeEvent: fc.Arbitrary<ScopeEvent> = fc.oneof(
  fc.record({ kind: fc.constant("loop_enter" as const), loop_id: fc.nat(20) }),
  fc.record({ kind: fc.constant("loop_exit" as const), loop_id: fc.nat(20) }),
  fc.record({ kind: fc.constant("call_enter" as const), call_site_id: fc.nat(20) }),
  fc.record({ kind: fc.constant("call_exit" as const), call_site_id: fc.nat(20) }),
);

const arbTraceEvent: fc.Arbitrary<TraceEvent> = fc.oneof(
  fc.record({ type: fc.constant("branch" as const), decision: arbBranchDecision }),
  fc.record({ type: fc.constant("scope" as const), event: arbScopeEvent }),
);

const arbPerformanceMetrics: fc.Arbitrary<PerformanceMetrics> = fc.record({
  wall_time_ms: fc.nat(10000),
  cpu_time_us: fc.nat(10000000),
  heap_used_bytes: fc.nat(100000000),
  heap_allocated_bytes: fc.nat(100000000),
});

const arbErrorInfo: fc.Arbitrary<ErrorInfo> = fc.record({
  error_type: arbIdent,
  message: arbShortString,
  stack: fc.option(arbShortString, { nil: null }),
});

const arbSideEffect: fc.Arbitrary<SideEffect> = fc.oneof(
  fc.record({ kind: fc.constant("console_output" as const), level: arbIdent, message: arbShortString }),
  fc.record({ kind: fc.constant("global_mutation" as const), name: arbIdent }),
  fc.record({
    kind: fc.constant("thrown_error" as const),
    error_type: arbIdent,
    message: arbShortString,
    stack: fc.option(arbShortString, { nil: null }),
  }),
);

const arbParamInfo: fc.Arbitrary<ParamInfo> = fc.record({
  name: arbIdent,
  type: arbTypeInfo,
});

const arbBranchInfo: fc.Arbitrary<BranchInfo> = fc.record({
  id: fc.nat(100),
  line: fc.integer({ min: 1, max: 500 }),
  condition_text: arbShortString,
  condition: fc.option(arbSymExpr, { nil: null }),
  branch_type: arbBranchType,
});

const arbFunctionAnalysis: fc.Arbitrary<FunctionAnalysis> = fc.record({
  name: arbIdent,
  exported: fc.boolean(),
  params: fc.array(arbParamInfo, { maxLength: 4 }),
  branches: fc.array(arbBranchInfo, { maxLength: 4 }),
  dependencies: fc.constant([]),
  return_type: arbTypeInfo,
  start_line: fc.integer({ min: 1, max: 500 }),
  end_line: fc.integer({ min: 1, max: 500 }),
});

// ---------------------------------------------------------------------------
// Arbitraries — setup types
// ---------------------------------------------------------------------------

const arbSetupLevel: fc.Arbitrary<SetupLevel> = fc.constantFrom(
  "session", "file", "function", "execution",
);

const arbSetupContextEntry: fc.Arbitrary<SetupContextEntry> = fc.record({
  level: arbSetupLevel,
  context: fc.oneof(fc.integer(), fc.string({ maxLength: 10 }), fc.constant(null), fc.record({ id: fc.nat(100) })),
});

const arbSetupContextStack: fc.Arbitrary<SetupContextStack> = fc.record({
  contexts: fc.array(arbSetupContextEntry, { maxLength: 4 }),
});

// ---------------------------------------------------------------------------
// Arbitraries — full protocol messages
// ---------------------------------------------------------------------------

const arbRequest: fc.Arbitrary<Request> = fc.oneof(
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("handshake" as const),
    capabilities: fc.array(arbIdent, { maxLength: 3 }),
  }) as fc.Arbitrary<HandshakeRequest>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("analyze" as const),
    file: arbIdent,
  }) as fc.Arbitrary<AnalyzeRequest>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("execute" as const),
    function: arbIdent,
    inputs: fc.array(fc.oneof(fc.integer(), fc.constant("hello"), fc.boolean()), { maxLength: 4 }),
    mocks: fc.constant([]),
  }) as fc.Arbitrary<ExecuteRequest>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("setup" as const),
    file: arbIdent,
    scope: arbIdent,
    level: arbSetupLevel,
  }) as fc.Arbitrary<SetupRequest>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("teardown" as const),
    scope: arbIdent,
    level: arbSetupLevel,
  }) as fc.Arbitrary<TeardownRequest>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("shutdown" as const),
  }) as fc.Arbitrary<ShutdownRequest>,
);

const arbResponse: fc.Arbitrary<Response> = fc.oneof(
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    status: fc.constant("handshake" as const),
    frontend_version: fc.constant(PROTOCOL_VERSION),
    language: fc.constant("typescript"),
    capabilities: fc.array(arbIdent, { maxLength: 3 }),
  }) as fc.Arbitrary<HandshakeResponse>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
